// Parse audit JSON and categorize findings
const raw = $input.first().json.stdout || '';
let audit;
try {
  audit = JSON.parse(raw.trim());
} catch (e) {
  return [{ json: { severity: 'CRITICAL', findings: ['Failed to parse audit JSON: ' + e.message], raw: raw.substring(0, 1000) } }];
}

if (audit.error) {
  return [{ json: { severity: 'WARNING', findings: [audit.error], raw: '' } }];
}

const findings = [];
const checks = audit.checks || {};

// Categorize each check
for (const [name, check] of Object.entries(checks)) {
  if (check.status === 'CRITICAL') {
    findings.push({ level: 'CRITICAL', check: name, details: JSON.stringify(check).substring(0, 300) });
  } else if (check.status === 'WARNING') {
    findings.push({ level: 'WARNING', check: name, details: JSON.stringify(check).substring(0, 300) });
  }
}

const critCount = findings.filter(f => f.level === 'CRITICAL').length;
const warnCount = findings.filter(f => f.level === 'WARNING').length;
const severity = critCount > 0 ? 'CRITICAL' : warnCount > 0 ? 'WARNING' : 'OK';

return [{ json: {
  severity,
  overall: audit.overall,
  critCount,
  warnCount,
  findings,
  date: audit.date,
  timestamp: audit.timestamp,
  sslCerts: checks.ssl_certs?.certs || [],
  fail2ban: checks.fail2ban || {},
  sshAttacks: checks.ssh_attacks?.failed_24h || 0,
  diskPercent: checks.resources?.disk_percent || 0,
  ramPercent: checks.resources?.ram_percent || 0
} }];

// Credential Rotation Reminder
// Check if any credentials are approaching expiry
const now = new Date();
const reminders = [];

const credentials = [
  { name: 'n8n API Key', expires: '2026-04-01', warnDaysBefore: 7 },
  { name: 'Telegram Bot Token', expires: null, rotateEveryDays: 180, lastRotated: '2026-01-01' },
  { name: 'SSH Keys (root)', expires: null, rotateEveryDays: 365, lastRotated: '2026-03-01' },
  { name: 'SSH Keys (agent)', expires: null, rotateEveryDays: 365, lastRotated: '2026-03-01' },
  { name: 'Groq API Key', expires: null, rotateEveryDays: 180, lastRotated: '2026-01-15' },
  { name: 'DB Password (PostgreSQL)', expires: null, rotateEveryDays: 90, lastRotated: '2026-01-01' },
  { name: 'Filebrowser Admin Password', expires: null, rotateEveryDays: 90, lastRotated: '2026-03-01' }
];

for (const cred of credentials) {
  if (cred.expires) {
    const expiryDate = new Date(cred.expires);
    const daysUntilExpiry = Math.ceil((expiryDate - now) / (1000 * 60 * 60 * 24));
    if (daysUntilExpiry <= (cred.warnDaysBefore || 7)) {
      reminders.push({ name: cred.name, type: 'EXPIRY', daysLeft: daysUntilExpiry, expires: cred.expires });
    }
  }
  if (cred.rotateEveryDays && cred.lastRotated) {
    const lastRotated = new Date(cred.lastRotated);
    const daysSinceRotation = Math.ceil((now - lastRotated) / (1000 * 60 * 60 * 24));
    if (daysSinceRotation >= cred.rotateEveryDays) {
      reminders.push({ name: cred.name, type: 'ROTATION_DUE', daysSinceRotation, recommendedEvery: cred.rotateEveryDays });
    }
  }
}

return [{ json: { hasReminders: reminders.length > 0, reminders, count: reminders.length } }];

